+    #[allow(unsafe_code)]
+    fn with_gf256_envs<F, R>(vars: &[(&str, &str)], f: F) -> R
+    where
+        F: FnOnce() -> R,
+    {
+        with_clean_gf256_env(|| {
+            for (key, value) in vars {
+                // SAFETY: tests serialize environment mutation with env_lock.
+                unsafe { std::env::set_var(key, value) };
+            }
+            f()
+        })
+    }
